function once(fn){
    let called = false
    return function(){
        if(!called){
            called = true
            fn.apply(this,arguments)
        }
    }
}

let call = once(function(){
    alert("函数被调用")
})
call()

var getSingle = function(fn){
    var result
    return function(){
        return result || (result = fn.apply(this,arguments) || true)//函数体默认return undefined，这里手动指定result为true，避免创建时没有指定return
    }
}
// 创建一个登陆框
